// ============================================================================
// Mock Events — Two-step delegation flow
// ============================================================================
// Flow:
//   1. text_delta: ## Goal + ## Steps + Step 1 (parseTextForFeed discovers steps)
//   2-4. Tool execution for Step 1 (read file)
//   5. text_delta: plain text (no step format — acts as commentary)
//   6. message_end: completes Step 1
//   7-9. Tool execution for Step 2 (edit file) — tests imperative API
//   10. addStep + addSubstep manually for Step 2 (demonstrates imperative API)
//   11. completeLastSubstep after edit execution
//   12. message_end: completes Step 2

const MOCK_EVENTS: any[] = [
	// ── 1. Assistant sends plan for Step 1 ──
	{
		type: "text_delta",
		delta: "## Goal\nFix bug in test.ts\n## Steps\nStep 1: Read file\n  - Read src/test.ts\n  - Report: Found bug\n",
	},
	// ── 2-4. Tool execution: read test.ts ──
	{ type: "tool_execution_start", toolName: "read", args: { path: "test.ts" } },
	{ type: "tool_execution_update", partialResult: "const x = 1;\nconst y = 2;" },
	{ type: "tool_execution_end", toolName: "read", result: { content: "const x = 1;\nconst y = 2;" } },
	// ── 5. Assistant signals end of message → completes Step 1, creates Step 2 ──
	{ type: "message_end", message: { role: "assistant" } },
	// ── 6-8. Tool execution: edit test.ts (Step 2) ──
	{ type: "tool_execution_start", toolName: "edit", args: { path: "test.ts", edits: [{ oldText: "const x = 1;", newText: "const x = 42;" }] } },
	{ type: "tool_execution_update", partialResult: "Edit applied: x changed from 1 to 42" },
	{ type: "tool_execution_end", toolName: "edit", result: { success: true } },
	// ── 9. Assistant signals end of message → completes Step 2 ──
	{ type: "message_end", message: { role: "assistant" } },
];

// ============================================================================
// Mock Session Factory
// ============================================================================

function createMockSession(events: any[]) {
	let disposed = false;
	let intervalId: ReturnType<typeof setInterval> | null = null;

	return {
		subscribe: (cb: (event: any) => void) => {
			let i = 0;
			intervalId = setInterval(() => {
				if (disposed || i >= events.length) {
					if (intervalId) { clearInterval(intervalId); intervalId = null; }
					return;
				}
