		case "tool_execution_start": {
			const substepLabel = toolCallToSubstep(event.toolName, event.args ?? {});
			const updatedFeed = addSubstep(feed, substepLabel);
			Object.assign(feed, updatedFeed);
			console.log(`  tool: ${event.toolName}`);
			console.log(`  args: ${JSON.stringify(event.args ?? {}).slice(0, 100)}`);
			break;
		}
		case "tool_execution_update": {
			if (updateActiveSubstepOutput) {
				const updatedFeed = updateActiveSubstepOutput(feed, event.partialResult ?? "");
				Object.assign(feed, updatedFeed);
