			break;
		}
		case "tool_execution_end": {
			const updatedFeed = completeLastSubstep(feed, JSON.stringify(event.result ?? {}).slice(0, 100));
			Object.assign(feed, updatedFeed);
			console.log(`  tool: ${event.toolName} completed`);
			break;
		}
		case "message_end": {
			// First message_end: complete Step 1, then create Step 2 imperatively
			if (feed.currentStep === 0 && feed.steps.length === 1 && !feed.steps[0].completed) {
				// 1. Complete Step 1 (advances currentStep to 1)
				let updatedFeed = completeCurrentStep(feed);
				Object.assign(feed, updatedFeed);

