						const newSteps = feed.steps.map((s: any, i: number) =>
							i === feed.currentStep ? { ...s, substeps: newSubsteps } : s
						);
						Object.assign(feed, { ...feed, steps: newSteps });
					}
				}
			} else {
				// Subsequent message_ends: just complete current step
				const updatedFeed = completeCurrentStep(feed);
				Object.assign(feed, updatedFeed);
			}
			console.log("  assistant message ended");
			break;
		}
	}
}

