```ts
function trimToBudget(lines: string[], budget: number): string[] {
    if (lines.length <= budget) return lines;
    // Find active step (has spinner)
    let activeIdx = -1;
    for (let i = 0; i < lines.length; i++) {
        if (/^[⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏]/.test(lines[i].trimStart())) {
            activeIdx = i;
            break;
        }
    }
    if (activeIdx >= 0) {
        // Keep everything from activeIdx onwards, and fill from top
        const beforeActive = lines.slice(0, activeIdx);
        const fromActive = lines.slice(activeIdx);
        const keepBefore = budget - fromActive.length;
        if (keepBefore <= 0) return fromActive.slice(fromActive.length - budget);
        return [...beforeActive.slice(0, keepBefore), ...fromActive];
    }
    // No active step — trim from top
    return lines.slice(lines.length - budget);
}
```

